package domain

import (
	"time"
)

// ResultSpec is the normalized output generated by any agent adapter.
type ResultSpec struct {
	Version            string            `json:"version"`
	RunID              string            `json:"run_id"`
	PhaseID            string            `json:"phase_id"`
	StepID             string            `json:"step_id"`
	AttemptID          string            `json:"attempt_id"`
	Adapter            string            `json:"adapter"`
	RequestedAdapter   string            `json:"requested_adapter"`
	State              StepState         `json:"state"`
	Summary            string            `json:"summary"`
	FilesChanged       []string          `json:"files_changed"`
	Validations        []ValidationResult `json:"validations"`
	NeedsHumanDecision bool              `json:"needs_human_decision"`
	Warnings           []string          `json:"warnings"`
	Questions          []string          `json:"questions"`
	Artifacts          map[string]string `json:"artifacts"`
	RawOutput          string            `json:"raw_output,omitempty"`
	RawOutputRef       string            `json:"raw_output_ref,omitempty"`
	// IsSimulation is true if generated by a stub for orchestrator validation.
	// NOT equivalent to real execution; used for dev/testing only.
	IsSimulation       bool              `json:"is_simulation"`
	Retryable          bool              `json:"retryable"`
	CreatedAt          time.Time         `json:"created_at"`
	UpdatedAt          time.Time         `json:"updated_at"`
}
